     6→const CODEOWNERS_MANIFEST_FILENAMES_BY_TEAM_PATH = 'codeowners-manifest/filenames-by-team.json';
     7→
     8→const teamName = process.env.TEAM_NAME;
     9→if (!teamName) {
    10→  console.error('ERROR: TEAM_NAME environment variable is required');
    11→  process.exit(1);
    12→}
    13→
    14→const outputDir = `./coverage/by-team/${createOwnerDirectory(teamName)}`;
    15→
    16→const codeownersFilePath = path.join(__dirname, CODEOWNERS_MANIFEST_FILENAMES_BY_TEAM_PATH);
    17→
    18→if (!fs.existsSync(codeownersFilePath)) {
    19→  console.error(`Codeowners file not found at ${codeownersFilePath} ...`);
    20→  console.error('Please run: yarn codeowners-manifest first to generate the mapping file');
    21→  process.exit(1);
    22→}
    23→
    24→const codeownersData = JSON.parse(fs.readFileSync(codeownersFilePath, 'utf8'));
    25→const teamFiles = codeownersData[teamName] || [];
    26→
    27→if (teamFiles.length === 0) {
    28→  console.error(`ERROR: No files found for team "${teamName}"`);
    29→  console.error('Available teams:', Object.keys(codeownersData).join(', '));
    30→  process.exit(1);
    31→}
    32→
    33→const sourceFiles = teamFiles.filter((file) => {
    34→  const ext = path.extname(file);
    35→  return (
    36→    ['.ts', '.tsx', '.js', '.jsx'].includes(ext) &&
    37→    !file.includes('.test.') &&
    38→    !file.includes('.spec.') &&
    39→    !file.includes('.story.') &&
    40→    !file.includes('.gen.ts') &&
    41→    !file.includes('.d.ts') &&
    42→    !file.endsWith('/types.ts')
    43→  );
    44→});
    45→
    46→const testFiles = teamFiles.filter((file) => {
    47→  const ext = path.extname(file);
    48→  return ['.ts', '.tsx', '.js', '.jsx'].includes(ext) && (file.includes('.test.') || file.includes('.spec.'));
    49→});
    50→
    51→if (testFiles.length === 0) {
    52→  console.log(`No test files found for team ${teamName}`);
    53→  process.exit(0);
    54→}
    55→
    56→console.log(
    57→  `🧪 Collecting coverage for ${sourceFiles.length} testable files and running ${testFiles.length} test files of ${teamFiles.length} files owned by ${teamName}.`
    58→);
    59→
    60→module.exports = {
    61→  ...baseConfig,
    62→
    63→  collectCoverage: true,
    64→  collectCoverageFrom: sourceFiles.map((file) => `<rootDir>/${file}`),
    65→  coverageReporters: ['none'],
    66→  coverageDirectory: '/tmp/jest-coverage-ignore',
    67→
    68→  coverageProvider: 'v8',
    69→  reporters: [
    70→    'default',
    71→    [
    72→      'jest-monocart-coverage',
    73→      {
    74→        name: `Coverage Report - ${teamName} owned files`,
    75→        outputDir: outputDir,
    76→        reports: ['console-summary', 'v8', 'json', 'lcov'],
    77→        sourceFilter: (coveredFile) => sourceFiles.includes(coveredFile),
    78→        all: {
    79→          dir: ['./packages', './public'],
    80→          filter: (filePath) => {
    81→            const relativePath = filePath.replace(process.cwd() + '/', '');
    82→            return sourceFiles.includes(relativePath);
    83→          },
    84→        },
    85→        cleanCache: true,
    86→        onEnd: (coverageResults) => {
    87→          console.log(`📄 Coverage report saved to file://${path.resolve(outputDir)}/index.html`);
    88→          // TODO: Emit coverage metrics https://github.com/grafana/grafana/issues/111208
    89→        },
    90→      },
    91→    ],
    92→  ],
    93→
    94→  testRegex: undefined,
    95→
    96→  testMatch: testFiles.map((file) => `<rootDir>/${file}`),
    97→};
    98→
    99→/**
   100→ * Create a filesystem-safe directory structure for different owner types
   101→ * @param {string} owner - CODEOWNERS owner (username, team, or email)
   102→ * @returns {string} Directory path relative to coverage/by-team/
   103→ */
   104→function createOwnerDirectory(owner) {
   105→  if (owner.includes('@') && owner.includes('/')) {
   106→    // Example: @grafana/dataviz-squad
   107→    const [org, team] = owner.substring(1).split('/');
   108→    return `teams/${org}/${team}`;
   109→  } else if (owner.startsWith('@')) {
   110→    // Example: @jesdavpet
   111→    return `users/${owner.substring(1)}`;
   112→  } else {
   113→    // Example: user@domain.tld
   114→    const [user, domain] = owner.split('@');
   115→    return `emails/${user}-at-${domain}`;
   116→  }
   117→}
